awk -F',' '
NR==1 {
    for (i=1; i<=NF; i++) headers[i]=$i
    ncols=NF
    next
}
{
    row=""
    for (i=1; i<=ncols; i++) {
        row = row sprintf("\"%s\":\"%s\"", headers[i], $i)
        if (i < ncols) row = row ","
    }
    rows[NR] = "{" row "}"
}
END {
    printf "["
    first=1
    for (r in rows) {
        if (!first) printf ","
        printf "%s", rows[r]
        first=0
    }
    printf "]"
}
' /data/users.csv | jq .

# Read headers
head -1 /data/users.csv | tr ',' '\n' > /tmp/headers.txt

# Build JSON using awk with a simpler approach
awk 'BEGIN{FS=","} 
NR==1 { for(i=1;i<=NF;i++) h[i]=$i; n=NF; next }
{
  printf "%s{", (NR>2 ? "," : "")
  for(i=1;i<=n;i++) {
    printf "\"%s\":\"%s\"", h[i], $i
    if(i<n) printf ","
  }
  printf "}"
}
END { }
' /data/users.csv | awk 'BEGIN{printf "["} {print} END{printf "]\n"}' | jq .

# Fully generic approach using only awk
