NR == 1 {
  n = NF
  for (i = 1; i <= NF; i++) h[i] = $i
  next
}
{
  if (NR > 2) printf ",\n"
  printf "  {"
  for (i = 1; i <= n; i++) {
    if (i > 1) printf ","
    printf "\"%s\":\"%s\"", h[i], $i
  }
  printf "}"
}
END { printf "\n" }
