input.commands:
awk '
BEGIN { first_heading_done = 0; toc = "" }
{
    lines[NR] = $0
}
END {
    # First pass: collect all headings (skip the first one) for TOC
    for (i = 1; i <= NR; i++) {
        if (lines[i] ~ /^#{1,2} /) {
            if (first_heading_done == 0) {
                first_heading_done = 1
                first_heading_line = i
            } else {
                # Extract heading text
                text = lines[i]
                gsub(/^#+ /, "", text)
                # Build anchor: lowercase, spaces to hyphens
                anchor = tolower(text)
                gsub(/ /, "-", anchor)
                toc = toc "- [" text "](#" anchor ")\n"
            }
        }
    }

    # Second pass: print with TOC inserted after first heading
    for (i = 1; i <= NR; i++) {
        print lines[i]
        if (i == first_heading_line) {
            print ""
            printf "%s", toc
        }
    }
}
' /doc/README.md > /doc/README.md.tmp && mv /doc/README.md.tmp /doc/README.md

