# Parse both files into associative arrays and compare
awk -F= '
    # Load v1.conf
    NR==FNR {
        if ($0 ~ /=/) {
            key = $1
            sub(/^[^=]*=/, "")
            v1[key] = $0
        }
        next
    }
    # Load v2.conf
    {
        if ($0 ~ /=/) {
            key = $1
            sub(/^[^=]*=/, "")
            v2[key] = $0
        }
    }
    END {
        # Removed keys (in v1 but not v2)
        n_removed = 0
        for (k in v1) {
            if (!(k in v2)) {
                removed[++n_removed] = k
            }
        }
        # Added keys (in v2 but not v1)
        n_added = 0
        for (k in v2) {
            if (!(k in v1)) {
                added[++n_added] = k
            }
        }
        # Changed keys (in both but different values)
        n_changed = 0
        for (k in v1) {
            if ((k in v2) && v1[k] != v2[k]) {
                changed[++n_changed] = k
            }
        }

        print "========================================="
        print "  Configuration Diff: v1.conf → v2.conf"
        print "========================================="

        print ""
        print "Added keys (" n_added "):"
        if (n_added == 0) print "  (none)"
        for (i = 1; i <= n_added; i++)
            printf "  + %-20s = %s\n", added[i], v2[added[i]]

        print ""
        print "Removed keys (" n_removed "):"
        if (n_removed == 0) print "  (none)"
        for (i = 1; i <= n_removed; i++)
            printf "  - %-20s = %s\n", removed[i], v1[removed[i]]

        print ""
        print "Changed values (" n_changed "):"
        if (n_changed == 0) print "  (none)"
        for (i = 1; i <= n_changed; i++)
            printf "  ~ %-20s : \"%s\" → \"%s\"\n", changed[i], v1[changed[i]], v2[changed[i]]

        print ""
        print "========================================="
    }
